import React, { useState, useEffect } from "react";
import axios from "axios";
import { motion } from "framer-motion";
import { Trophy, Crown } from "lucide-react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer
} from "recharts";

const API = "http://127.0.0.1:8001/api";

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState("");

  const [stats, setStats] = useState(null);
  const [matches, setMatches] = useState([]);

  const [graphData, setGraphData] = useState([]);

  // LOAD DATA
  const loadData = async () => {
    const m = await axios.get(`${API}/matches`);
    const s = await axios.get(`${API}/stats`);

    setMatches(m.data);
    setStats(s.data);

    // build graph data
    let yash = 0;
    let nishant = 0;

    const g = m.data
      .slice()
      .reverse()
      .map((match) => {
        yash += match.yash_points;
        nishant += match.nishant_points;

        return {
          date: match.match_date,
          Yash: yash,
          Nishant: nishant
        };
      });

    setGraphData(g);
  };

  useEffect(() => {
    if (localStorage.getItem("auth") === "true") {
      setIsAuthenticated(true);
      loadData();
    }
  }, []);

  const handleLogin = async () => {
    const res = await axios.post(`${API}/auth/login`, { password });
    if (res.data.success) {
      localStorage.setItem("auth", "true");
      setIsAuthenticated(true);
      loadData();
    } else {
      alert("Wrong password");
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="p-6 bg-white/10 rounded-xl backdrop-blur">
          <h1 className="mb-3">Chess Tournament</h1>
          <input
            type="password"
            onChange={(e) => setPassword(e.target.value)}
            className="p-2 mb-2 bg-white/20 rounded w-full"
          />
          <button
            onClick={handleLogin}
            className="bg-green-600 w-full p-2 rounded"
          >
            Enter
          </button>
        </div>
      </div>
    );
  }

  const leader =
    stats?.yash_total_points > stats?.nishant_total_points
      ? "Yash"
      : stats?.yash_total_points < stats?.nishant_total_points
      ? "Nishant"
      : "Draw";

  return (
    <div className="min-h-screen bg-black text-white p-4">

      {/* HEADER */}
      <div className="flex justify-between mb-6">
        <h1 className="flex items-center gap-2 text-xl">
          <Trophy /> Chess Arena
        </h1>
        <button
          onClick={() => {
            localStorage.clear();
            window.location.reload();
          }}
        >
          Logout
        </button>
      </div>

      {/* WINNER CARD */}
      <motion.div
        initial={{ scale: 0.9 }}
        animate={{ scale: 1 }}
        className="p-6 mb-6 rounded-xl bg-gradient-to-r from-green-500 to-emerald-600 text-black text-center"
      >
        <Crown className="mx-auto mb-2" size={40} />
        <h2 className="text-xl font-bold">
          {leader === "Draw" ? "It's Close!" : `${leader} is Leading`}
        </h2>
      </motion.div>

      {/* SCORE */}
      {stats && (
        <div className="grid grid-cols-2 gap-4 mb-6">
          <motion.div
            key={stats.yash_total_points}
            initial={{ scale: 1.2 }}
            animate={{ scale: 1 }}
            className="p-4 bg-green-600 rounded-xl text-center"
          >
            <h2 className="text-2xl font-bold">
              {stats.yash_total_points}
            </h2>
            <p>Yash</p>
          </motion.div>

          <motion.div
            key={stats.nishant_total_points}
            initial={{ scale: 1.2 }}
            animate={{ scale: 1 }}
            className="p-4 bg-gray-700 rounded-xl text-center"
          >
            <h2 className="text-2xl font-bold">
              {stats.nishant_total_points}
            </h2>
            <p>Nishant</p>
          </motion.div>
        </div>
      )}

      {/* GRAPH */}
      <div className="bg-white/10 p-4 rounded-xl mb-6">
        <h2 className="mb-3">Leaderboard Trend</h2>

        <ResponsiveContainer width="100%" height={250}>
          <LineChart data={graphData}>
            <XAxis dataKey="date" stroke="#aaa" />
            <YAxis stroke="#aaa" />
            <Tooltip />
            <Line type="monotone" dataKey="Yash" stroke="#22c55e" />
            <Line type="monotone" dataKey="Nishant" stroke="#8884d8" />
          </LineChart>
        </ResponsiveContainer>
      </div>

      {/* MATCH LIST */}
      <div>
        {matches.map((m) => (
          <motion.div
            key={m.id}
            whileHover={{ scale: 1.02 }}
            className="p-3 mb-2 bg-white/10 rounded-xl flex justify-between"
          >
            <div>
              <p>{m.match_date}</p>
              <p className="text-sm text-gray-400">{m.notes}</p>
            </div>

            <span
              className={`px-2 py-1 rounded ${
                m.winner === "Yash"
                  ? "bg-green-500"
                  : m.winner === "Nishant"
                  ? "bg-gray-500"
                  : "bg-yellow-500"
              }`}
            >
              {m.winner}
            </span>
          </motion.div>
        ))}
      </div>
    </div>
  );
}
